var CONVERSATIONS_EL_NL = [
{ title: "Παραγγελία σε καφέ", scene: "Βρίσκεσαι σε ένα μικρό καφέ στο Άμστερνταμ κοντά σε κανάλι. Θέλεις να παραγγείλεις καφέ και κάτι μικρό για φαγητό.", lines: [{ who: "them", nl: "Goedemorgen, wat wilt u bestellen?", el: "Καλημέρα, τι θα θέλατε να παραγγείλετε;" }, { who: "you", nl: "Goedemorgen, een koffie, alstublieft.", el: "Καλημέρα, έναν καφέ, παρακαλώ." }, { who: "them", nl: "Met melk of zonder melk?", el: "Με γάλα ή χωρίς γάλα;" }, { who: "you", nl: "Met melk, graag.", el: "Με γάλα, παρακαλώ." }, { who: "them", nl: "Wilt u ook iets eten?", el: "Θέλετε και κάτι να φάτε;" }, { who: "you", nl: "Ja, een broodje kaas, alstublieft.", el: "Ναι, ένα σάντουιτς με τυρί, παρακαλώ." }, { who: "them", nl: "Dat is alles?", el: "Αυτά είναι όλα;" }, { who: "you", nl: "Ja, dat is alles.", el: "Ναι, αυτά είναι όλα." }, { who: "them", nl: "Dat is acht euro.", el: "Είναι οκτώ ευρώ." }, { who: "you", nl: "Kan ik met kaart betalen?", el: "Μπορώ να πληρώσω με κάρτα;" }, { who: "them", nl: "Ja, natuurlijk.", el: "Ναι, φυσικά." }, { who: "you", nl: "Dank u wel.", el: "Ευχαριστώ πολύ." }] },
{ title: "Check-in σε ξενοδοχείο", scene: "Φτάνεις σε ξενοδοχείο στην Ουτρέχτη μετά από ταξίδι με τρένο. Έχεις κράτηση και θέλεις να μάθεις για το πρωινό.", lines: [{ who: "them", nl: "Goedenavond, welkom in ons hotel.", el: "Καλησπέρα, καλώς ήρθατε στο ξενοδοχείο μας." }, { who: "you", nl: "Goedenavond, ik heb een reservering.", el: "Καλησπέρα, έχω κράτηση." }, { who: "them", nl: "Op welke naam?", el: "Σε ποιο όνομα;" }, { who: "you", nl: "Op naam van Papadopoulos.", el: "Στο όνομα Παπαδόπουλος." }, { who: "them", nl: "Mag ik uw paspoort zien?", el: "Μπορώ να δω το διαβατήριό σας;" }, { who: "you", nl: "Ja, alstublieft.", el: "Ναι, ορίστε." }, { who: "them", nl: "U heeft kamer drie.", el: "Έχετε το δωμάτιο τρία." }, { who: "you", nl: "Is ontbijt inbegrepen?", el: "Περιλαμβάνεται πρωινό;" }, { who: "them", nl: "Ja, ontbijt is van zeven tot tien.", el: "Ναι, το πρωινό είναι από τις επτά μέχρι τις δέκα." }, { who: "you", nl: "Waar is de lift?", el: "Πού είναι το ασανσέρ;" }, { who: "them", nl: "De lift is rechts.", el: "Το ασανσέρ είναι δεξιά." }, { who: "you", nl: "Dank u wel voor uw hulp.", el: "Ευχαριστώ πολύ για τη βοήθειά σας." }] },
{ title: "Ζητώντας οδηγίες", scene: "Περπατάς στο Ρότερνταμ και ψάχνεις το μουσείο. Σταματάς έναν περαστικό και ζητάς απλές οδηγίες.", lines: [{ who: "you", nl: "Sorry, kunt u mij helpen?", el: "Συγγνώμη, μπορείτε να με βοηθήσετε;" }, { who: "them", nl: "Ja, natuurlijk.", el: "Ναι, φυσικά." }, { who: "you", nl: "Ik zoek het museum.", el: "Ψάχνω το μουσείο." }, { who: "them", nl: "Het museum is niet ver.", el: "Το μουσείο δεν είναι μακριά." }, { who: "you", nl: "Waar moet ik heen?", el: "Πού πρέπει να πάω;" }, { who: "them", nl: "Loop rechtdoor en ga dan links.", el: "Περπατήστε ευθεία και μετά πηγαίνετε αριστερά." }, { who: "you", nl: "Is het om de hoek?", el: "Είναι στη γωνία;" }, { who: "them", nl: "Ja, bij de brug.", el: "Ναι, κοντά στη γέφυρα." }, { who: "you", nl: "Kunt u dat herhalen?", el: "Μπορείτε να το επαναλάβετε;" }, { who: "them", nl: "Rechtdoor, dan links bij de brug.", el: "Ευθεία, μετά αριστερά στη γέφυρα." }, { who: "you", nl: "Bedankt, ik begrijp het.", el: "Ευχαριστώ, το καταλαβαίνω." }, { who: "them", nl: "Graag gedaan.", el: "Παρακαλώ." }] },
{ title: "Δείπνο σε εστιατόριο", scene: "Κάθεσαι σε εστιατόριο στη Χάγη και θέλεις να ζητήσεις το μενού, να παραγγείλεις και να πληρώσεις. Ο σερβιτόρος μιλά καθαρά και ευγενικά.", lines: [{ who: "them", nl: "Goedenavond, heeft u een reservering?", el: "Καλησπέρα, έχετε κράτηση;" }, { who: "you", nl: "Nee, heeft u een tafel voor twee?", el: "Όχι, έχετε τραπέζι για δύο;" }, { who: "them", nl: "Ja, natuurlijk, hier alstublieft.", el: "Ναι, φυσικά, εδώ παρακαλώ." }, { who: "you", nl: "Mag ik het menu?", el: "Μπορώ να έχω το μενού;" }, { who: "them", nl: "Ja, hier is het menu.", el: "Ναι, εδώ είναι το μενού." }, { who: "you", nl: "Heeft u vegetarisch eten?", el: "Έχετε χορτοφαγικό φαγητό;" }, { who: "them", nl: "Ja, we hebben soep en groente.", el: "Ναι, έχουμε σούπα και λαχανικά." }, { who: "you", nl: "Ik wil graag de soep.", el: "Θα ήθελα τη σούπα." }, { who: "them", nl: "Wilt u ook iets drinken?", el: "Θέλετε και κάτι να πιείτε;" }, { who: "you", nl: "Water, alstublieft.", el: "Νερό, παρακαλώ." }, { who: "them", nl: "Prima, ik kom zo terug.", el: "Ωραία, επιστρέφω αμέσως." }, { who: "you", nl: "Dank u wel.", el: "Ευχαριστώ πολύ." }] },
{ title: "Αγορά εισιτηρίου τρένου", scene: "Είσαι στον σταθμό του Λέιντεν και θέλεις να πας στο Άμστερνταμ. Ρωτάς για εισιτήριο, αποβάθρα και πιθανή αλλαγή τρένου.", lines: [{ who: "them", nl: "Goedemiddag, waar wilt u heen?", el: "Καλό μεσημέρι, πού θέλετε να πάτε;" }, { who: "you", nl: "Naar Amsterdam, alstublieft.", el: "Για Άμστερνταμ, παρακαλώ." }, { who: "them", nl: "Enkele reis of retour?", el: "Απλή διαδρομή ή με επιστροφή;" }, { who: "you", nl: "Een retour, graag.", el: "Με επιστροφή, παρακαλώ." }, { who: "them", nl: "Dat is twintig euro.", el: "Είναι είκοσι ευρώ." }, { who: "you", nl: "Kan ik met kaart betalen?", el: "Μπορώ να πληρώσω με κάρτα;" }, { who: "them", nl: "Ja, dat kan.", el: "Ναι, μπορείτε." }, { who: "you", nl: "Welk perron?", el: "Ποια αποβάθρα;" }, { who: "them", nl: "Perron vier.", el: "Αποβάθρα τέσσερα." }, { who: "you", nl: "Moet ik overstappen?", el: "Πρέπει να αλλάξω τρένο;" }, { who: "them", nl: "Nee, het is een directe trein.", el: "Όχι, είναι απευθείας τρένο." }, { who: "you", nl: "Bedankt.", el: "Ευχαριστώ." }] },
{ title: "Ψώνια σε αγορά", scene: "Βρίσκεσαι σε υπαίθρια αγορά στην Ολλανδία και κοιτάζεις τσάντες και μικρά δώρα. Θέλεις να ρωτήσεις τιμή και να πληρώσεις με κάρτα.", lines: [{ who: "them", nl: "Hallo, kan ik u helpen?", el: "Γεια σας, μπορώ να σας βοηθήσω;" }, { who: "you", nl: "Hallo, hoeveel kost dit?", el: "Γεια σας, πόσο κοστίζει αυτό;" }, { who: "them", nl: "Dat kost vijftien euro.", el: "Κοστίζει δεκαπέντε ευρώ." }, { who: "you", nl: "Heeft u een andere kleur?", el: "Έχετε άλλο χρώμα;" }, { who: "them", nl: "Ja, we hebben blauw en zwart.", el: "Ναι, έχουμε μπλε και μαύρο." }, { who: "you", nl: "Ik neem deze.", el: "Θα πάρω αυτό." }, { who: "them", nl: "Wilt u een tas?", el: "Θέλετε σακούλα;" }, { who: "you", nl: "Ja, alstublieft.", el: "Ναι, παρακαλώ." }, { who: "them", nl: "Wilt u contant betalen?", el: "Θέλετε να πληρώσετε με μετρητά;" }, { who: "you", nl: "Nee, met kaart, graag.", el: "Όχι, με κάρτα, παρακαλώ." }, { who: "them", nl: "Prima.", el: "Ωραία." }, { who: "you", nl: "Mag ik de bon?", el: "Μπορώ να έχω την απόδειξη;" }] },
{ title: "Στο φαρμακείο", scene: "Δεν αισθάνεσαι καλά και μπαίνεις σε φαρμακείο στο Άμστερνταμ. Θέλεις κάτι για πονοκέφαλο και εξηγείς ότι έχεις αλλεργία.", lines: [{ who: "them", nl: "Goedemiddag, kan ik u helpen?", el: "Καλό μεσημέρι, μπορώ να σας βοηθήσω;" }, { who: "you", nl: "Ik voel me niet goed.", el: "Δεν αισθάνομαι καλά." }, { who: "them", nl: "Wat is het probleem?", el: "Ποιο είναι το πρόβλημα;" }, { who: "you", nl: "Ik heb hoofdpijn.", el: "Έχω πονοκέφαλο." }, { who: "them", nl: "Heeft u ook koorts?", el: "Έχετε και πυρετό;" }, { who: "you", nl: "Nee, geen koorts.", el: "Όχι, χωρίς πυρετό." }, { who: "them", nl: "Heeft u een allergie?", el: "Έχετε αλλεργία;" }, { who: "you", nl: "Ja, ik ben allergisch voor noten.", el: "Ναι, είμαι αλλεργικός στους ξηρούς καρπούς." }, { who: "them", nl: "Dan geef ik u dit medicijn.", el: "Τότε σας δίνω αυτό το φάρμακο." }, { who: "you", nl: "Hoeveel kost het?", el: "Πόσο κοστίζει;" }, { who: "them", nl: "Zes euro.", el: "Έξι ευρώ." }, { who: "you", nl: "Dank u wel voor uw hulp.", el: "Ευχαριστώ πολύ για τη βοήθειά σας." }] },
{ title: "Μικρή συζήτηση με ντόπιο", scene: "Κάθεσαι σε πάρκο στην Ουτρέχτη και ένας ντόπιος ξεκινά φιλική κουβέντα. Μιλάς απλά για την πόλη, το ταξίδι και τα ολλανδικά που μαθαίνεις.", lines: [{ who: "you", nl: "Hallo, is deze plek vrij?", el: "Γεια, είναι ελεύθερο αυτό το μέρος;" }, { who: "them", nl: "Ja, natuurlijk.", el: "Ναι, φυσικά." }, { who: "you", nl: "Dank je, het park is mooi.", el: "Ευχαριστώ, το πάρκο είναι όμορφο." }, { who: "them", nl: "Ja, het is hier rustig.", el: "Ναι, εδώ είναι ήσυχα." }, { who: "you", nl: "Ik kom uit Griekenland.", el: "Είμαι από την Ελλάδα." }, { who: "them", nl: "Leuk, ben je hier op vakantie?", el: "Ωραία, είσαι εδώ για διακοπές;" }, { who: "you", nl: "Ja, ik reis door Nederland.", el: "Ναι, ταξιδεύω στην Ολλανδία." }, { who: "them", nl: "Spreek je Nederlands?", el: "Μιλάς ολλανδικά;" }, { who: "you", nl: "Een beetje, ik leer Nederlands.", el: "Λίγο, μαθαίνω ολλανδικά." }, { who: "them", nl: "Dat is goed!", el: "Αυτό είναι καλό!" }, { who: "you", nl: "Ik vind Utrecht erg leuk.", el: "Μου αρέσει πολύ η Ουτρέχτη." }, { who: "them", nl: "Welkom en veel plezier.", el: "Καλώς ήρθες και να περάσεις όμορφα." }] }
];
